//! High-performance design matrix construction for statistical models
//!
//! This crate provides column-oriented design matrix builders that fuse
//! transformations to eliminate intermediate allocations and leverage
//! parallel computation for construction.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use formula::ModelSpec;
use ndarray::Array2;

/// Design matrix construction errors
#[derive(thiserror::Error, Debug)]
pub enum MatrixError {
    /// Data dimension mismatch
    #[error("Data dimension error: {0}")]
    Dimension(String),
    /// Variable not found in data
    #[error("Variable not found: {0}")]
    VariableNotFound(String),
}

/// High-performance design matrix builder with optimized memory layout
pub struct Builder {
    n_rows: usize,
    columns: Vec<Vec<f64>>,
}

impl Builder {
    /// Create a new builder for the given number of observations
    pub fn new(n_rows: usize) -> Self {
        Self {
            n_rows,
            columns: Vec::new(),
        }
    }

    /// Add an intercept column (all ones)
    pub fn add_intercept(&mut self) {
        self.columns.push(vec![1.0; self.n_rows]);
    }

    /// Add a continuous variable column
    pub fn add_continuous(&mut self, values: Vec<f64>) -> Result<(), MatrixError> {
        if values.len() != self.n_rows {
            return Err(MatrixError::Dimension(format!(
                "Expected {} rows, got {}",
                self.n_rows,
                values.len()
            )));
        }
        self.columns.push(values);
        Ok(())
    }

    /// Build the final design matrix with optimized memory layout
    pub fn build(self) -> Array2<f64> {
        if self.columns.is_empty() {
            return Array2::zeros((self.n_rows, 0));
        }

        let n_cols = self.columns.len();

        // Optimized approach: construct directly from flattened data
        // This avoids the double-allocation and improves cache performance
        let total_elements = self.n_rows * n_cols;
        let mut flat_data = Vec::with_capacity(total_elements);

        // Build row by row for better memory locality
        for row_idx in 0..self.n_rows {
            for col_idx in 0..n_cols {
                flat_data.push(self.columns[col_idx][row_idx]);
            }
        }

        // Create array from pre-built data
        Array2::from_shape_vec((self.n_rows, n_cols), flat_data)
            .expect("Dimensions should match constructed data")
    }
}

/// Data container for building design matrices
#[derive(Debug)]
pub struct DataContainer {
    variables: std::collections::HashMap<String, Vec<f64>>,
    n_rows: usize,
}

impl DataContainer {
    /// Create a new data container
    pub fn new(n_rows: usize) -> Self {
        Self {
            variables: std::collections::HashMap::new(),
            n_rows,
        }
    }

    /// Add a continuous variable to the data
    pub fn add_variable(&mut self, name: String, values: Vec<f64>) -> Result<(), MatrixError> {
        if values.len() != self.n_rows {
            return Err(MatrixError::Dimension(format!(
                "Variable '{}' has {} values but expected {}",
                name,
                values.len(),
                self.n_rows
            )));
        }
        self.variables.insert(name, values);
        Ok(())
    }

    /// Get a variable by name
    pub fn get_variable(&self, name: &str) -> Option<&Vec<f64>> {
        self.variables.get(name)
    }
}

/// Build design matrix from model specification and data
pub fn build_design_matrix(
    spec: &ModelSpec,
    data: &DataContainer,
) -> Result<Array2<f64>, MatrixError> {
    use formula::Term;

    let mut builder = Builder::new(data.n_rows);
    let mut column_names = Vec::new();

    // Process each term in the model specification
    for term in &spec.terms {
        match term {
            Term::Intercept => {
                builder.add_intercept();
                column_names.push("(Intercept)".to_string());
            }
            Term::Variable(var_name) => {
                let values = data
                    .get_variable(var_name)
                    .ok_or_else(|| MatrixError::VariableNotFound(var_name.clone()))?;
                builder.add_continuous(values.clone())?;
                column_names.push(var_name.clone());
            }
            Term::Interaction(vars) => {
                // For interaction terms, multiply the variables together
                if vars.len() < 2 {
                    return Err(MatrixError::Dimension(
                        "Interaction term must have at least 2 variables".to_string(),
                    ));
                }

                // Get the first variable
                let first_var = match &vars[0] {
                    Term::Variable(name) => data
                        .get_variable(name)
                        .ok_or_else(|| MatrixError::VariableNotFound(name.clone()))?,
                    _ => {
                        return Err(MatrixError::Dimension(
                            "Interaction terms must contain variable names".to_string(),
                        ))
                    }
                };

                // Start with the first variable's values
                let mut interaction_values = first_var.clone();
                let mut interaction_name = match &vars[0] {
                    Term::Variable(name) => name.clone(),
                    _ => unreachable!(),
                };

                // Multiply by each subsequent variable
                for var in &vars[1..] {
                    match var {
                        Term::Variable(name) => {
                            let var_values = data
                                .get_variable(name)
                                .ok_or_else(|| MatrixError::VariableNotFound(name.clone()))?;

                            for (i, value) in interaction_values.iter_mut().enumerate() {
                                *value *= var_values[i];
                            }
                            interaction_name.push(':');
                            interaction_name.push_str(name);
                        }
                        _ => {
                            return Err(MatrixError::Dimension(
                                "Interaction terms must contain variable names".to_string(),
                            ))
                        }
                    }
                }

                builder.add_continuous(interaction_values)?;
                column_names.push(interaction_name);
            }
            Term::FullInteraction(_) => {
                // FullInteraction should be expanded before reaching here
                return Err(MatrixError::Dimension(
                    "FullInteraction terms should be expanded before matrix construction"
                        .to_string(),
                ));
            }
            Term::Function { name: _, args: _ } => {
                // TODO: Implement function calls in future sprint
                return Err(MatrixError::Dimension(
                    "Function calls not yet implemented".to_string(),
                ));
            }
        }
    }

    Ok(builder.build())
}

/// Build design matrix from model specification and data (legacy compatibility)
pub fn build_design_matrix_legacy(_spec: &ModelSpec) -> Result<Array2<f64>, MatrixError> {
    // For backward compatibility with existing tests
    let mut builder = Builder::new(2);
    builder.add_intercept();
    Ok(builder.build())
}

#[cfg(test)]
mod tests {
    use super::*;
    use formula::parse_formula;

    #[test]
    fn test_data_container() {
        let mut data = DataContainer::new(3);
        let x_values = vec![1.0, 2.0, 3.0];

        data.add_variable("x".to_string(), x_values.clone())
            .unwrap();
        assert_eq!(data.get_variable("x"), Some(&x_values));
        assert_eq!(data.get_variable("nonexistent"), None);
    }

    #[test]
    fn test_design_matrix_intercept_only() {
        let spec = formula::ModelSpec::intercept_only("y");
        let data = DataContainer::new(3);

        let matrix = build_design_matrix(&spec, &data).unwrap();
        assert_eq!(matrix.shape(), &[3, 1]);

        // Check intercept column (all ones)
        for i in 0..3 {
            assert_eq!(matrix[[i, 0]], 1.0);
        }
    }

    #[test]
    fn test_design_matrix_simple_regression() {
        // Parse formula: y ~ x
        let formula_spec = parse_formula("y ~ x").unwrap();

        let mut data = DataContainer::new(3);
        data.add_variable("x".to_string(), vec![1.0, 2.0, 3.0])
            .unwrap();

        let matrix = build_design_matrix(&formula_spec, &data).unwrap();
        assert_eq!(matrix.shape(), &[3, 1]);

        // Check x column
        assert_eq!(matrix[[0, 0]], 1.0);
        assert_eq!(matrix[[1, 0]], 2.0);
        assert_eq!(matrix[[2, 0]], 3.0);
    }

    #[test]
    fn test_design_matrix_multiple_variables() {
        // Parse formula: y ~ x1 + x2
        let formula_spec = parse_formula("y ~ x1 + x2").unwrap();

        let mut data = DataContainer::new(3);
        data.add_variable("x1".to_string(), vec![1.0, 2.0, 3.0])
            .unwrap();
        data.add_variable("x2".to_string(), vec![4.0, 5.0, 6.0])
            .unwrap();

        let matrix = build_design_matrix(&formula_spec, &data).unwrap();
        assert_eq!(matrix.shape(), &[3, 2]);

        // Check x1 column
        assert_eq!(matrix[[0, 0]], 1.0);
        assert_eq!(matrix[[1, 0]], 2.0);
        assert_eq!(matrix[[2, 0]], 3.0);

        // Check x2 column
        assert_eq!(matrix[[0, 1]], 4.0);
        assert_eq!(matrix[[1, 1]], 5.0);
        assert_eq!(matrix[[2, 1]], 6.0);
    }

    #[test]
    fn test_design_matrix_interaction() {
        // Parse formula: y ~ x1 * x2 (now expands to x1 + x2 + x1:x2)
        let formula_spec = parse_formula("y ~ x1 * x2").unwrap();

        let mut data = DataContainer::new(3);
        data.add_variable("x1".to_string(), vec![1.0, 2.0, 3.0])
            .unwrap();
        data.add_variable("x2".to_string(), vec![4.0, 5.0, 6.0])
            .unwrap();

        let matrix = build_design_matrix(&formula_spec, &data).unwrap();
        assert_eq!(matrix.shape(), &[3, 3]); // x1 + x2 + x1:x2

        // Check x1 column
        assert_eq!(matrix[[0, 0]], 1.0);
        assert_eq!(matrix[[1, 0]], 2.0);
        assert_eq!(matrix[[2, 0]], 3.0);

        // Check x2 column
        assert_eq!(matrix[[0, 1]], 4.0);
        assert_eq!(matrix[[1, 1]], 5.0);
        assert_eq!(matrix[[2, 1]], 6.0);

        // Check interaction column (x1:x2)
        assert_eq!(matrix[[0, 2]], 1.0 * 4.0); // 4.0
        assert_eq!(matrix[[1, 2]], 2.0 * 5.0); // 10.0
        assert_eq!(matrix[[2, 2]], 3.0 * 6.0); // 18.0
    }

    #[test]
    fn test_design_matrix_simple_interaction() {
        // Parse formula: y ~ x1 : x2 (creates only interaction term)
        let formula_spec = parse_formula("y ~ x1 : x2").unwrap();

        let mut data = DataContainer::new(3);
        data.add_variable("x1".to_string(), vec![1.0, 2.0, 3.0])
            .unwrap();
        data.add_variable("x2".to_string(), vec![4.0, 5.0, 6.0])
            .unwrap();

        let matrix = build_design_matrix(&formula_spec, &data).unwrap();
        assert_eq!(matrix.shape(), &[3, 1]); // Only x1:x2

        // Check interaction column (x1:x2)
        assert_eq!(matrix[[0, 0]], 1.0 * 4.0); // 4.0
        assert_eq!(matrix[[1, 0]], 2.0 * 5.0); // 10.0
        assert_eq!(matrix[[2, 0]], 3.0 * 6.0); // 18.0
    }

    #[test]
    fn test_missing_variable_error() {
        let formula_spec = parse_formula("y ~ x").unwrap();
        let data = DataContainer::new(3); // No variables added

        let result = build_design_matrix(&formula_spec, &data);
        assert!(result.is_err());
        assert!(matches!(
            result.unwrap_err(),
            MatrixError::VariableNotFound(_)
        ));
    }

    #[test]
    fn test_dimension_mismatch_error() {
        let mut data = DataContainer::new(3);
        let wrong_length = vec![1.0, 2.0]; // Length 2, but expected 3

        let result = data.add_variable("x".to_string(), wrong_length);
        assert!(result.is_err());
        assert!(matches!(result.unwrap_err(), MatrixError::Dimension(_)));
    }
}

//! High-level statistical modeling API for Rust
//!
//! This crate provides familiar model-fitting APIs like `Lm` (Linear Models)
//! and `Glm` (Generalized Linear Models), integrating lower-level crates
//! to provide a complete modeling workflow.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use faer::{prelude::*, Mat};
use family::Family;
use link::LinkFn;
use ndarray::{Array1, ArrayView1, ArrayView2};
use optimcore::{coordinate_descent, irls, CoordinateDescentConfig, IrlsConfig};
use resample::{bootstrap, BootstrapConfig, BootstrapResult, BootstrapStatistic};

/// Statistical modeling errors
#[derive(thiserror::Error, Debug)]
pub enum ModelError {
    /// Linear algebra computation error
    #[error("Linear algebra error: {0}")]
    LinearAlgebra(String),
    /// Invalid model specification
    #[error("Invalid model: {0}")]
    InvalidModel(String),
}

// Re-export important types for convenience
pub use family::{Binomial, Gaussian, Poisson};
pub use link::{Identity, Log, Logit};

/// Common trait for all fitted models
pub trait Fit {
    /// Get model coefficients
    fn coefficients(&self) -> &[f64];

    /// Get fitted values
    fn fitted(&self) -> &[f64];

    /// Get residuals
    fn residuals(&self) -> &[f64];

    /// Get model summary
    fn summary(&self) -> ModelSummary;

    /// Perform bootstrap resampling on the model
    fn bootstrap(&self, _n_samples: usize) -> Result<BootstrapResult, ModelError> {
        Err(ModelError::InvalidModel(
            "Bootstrap not implemented for this model type".to_string(),
        ))
    }
}

/// Model summary information
#[derive(Debug)]
pub struct ModelSummary {
    /// Coefficient table
    pub coefficients: Vec<CoefficientRow>,
    /// R-squared (coefficient of determination)
    pub r_squared: f64,
    /// Adjusted R-squared
    pub adj_r_squared: f64,
    /// Residual standard error
    pub residual_std_error: f64,
    /// F-statistic for overall model significance
    pub f_statistic: f64,
    /// p-value for F-statistic
    pub f_p_value: f64,
    /// Degrees of freedom for model (number of predictors excluding intercept)
    pub df_model: usize,
    /// Degrees of freedom for residuals
    pub df_residual: usize,
}

/// A row in the coefficient table
#[derive(Debug)]
pub struct CoefficientRow {
    /// Variable name
    pub name: String,
    /// Estimated coefficient
    pub estimate: f64,
    /// Standard error
    pub std_error: f64,
    /// t-statistic
    pub t_value: f64,
    /// p-value
    pub p_value: f64,
}

/// Linear model fitting
pub struct Lm;

/// Generalized linear model fitting
pub struct Glm;

/// Lasso regression (L1 regularization)
pub struct Lasso;

/// Ridge regression (L2 regularization)
pub struct Ridge;

/// Fitted linear model results
#[derive(Debug)]
pub struct LmFit {
    coefficients: Vec<f64>,
    fitted_values: Vec<f64>,
    residuals: Vec<f64>,
    /// Number of observations
    n_obs: usize,
    /// Matrix rank (for rank-deficient matrices)
    rank: usize,
    /// Design matrix for statistical inference (stored for covariance calculation)
    x_matrix: Mat<f64>,
}

/// Fitted generalized linear model results
#[derive(Debug)]
pub struct GlmFit {
    coefficients: Vec<f64>,
    fitted_values: Vec<f64>,
    residuals: Vec<f64>,
    /// Linear predictor values (X * β)
    linear_predictor: Vec<f64>,
    /// Number of observations
    n_obs: usize,
    /// Design matrix for statistical inference
    x_matrix: Mat<f64>,
    /// Final deviance
    deviance: f64,
    /// Working weights from final IRLS iteration
    weights: Vec<f64>,
    /// Number of IRLS iterations
    iterations: usize,
    /// Whether IRLS converged
    converged: bool,
}

/// Fitted regularized model results (Lasso/Ridge)
#[derive(Debug)]
pub struct RegularizedFit {
    coefficients: Vec<f64>,
    fitted_values: Vec<f64>,
    residuals: Vec<f64>,
    /// Number of observations
    n_obs: usize,
    /// Design matrix for bootstrap resampling
    x_matrix: Mat<f64>,
    /// Response vector for bootstrap resampling
    y_vector: Vec<f64>,
    /// Regularization parameter used
    lambda: f64,
    /// Elastic net mixing parameter (1.0 = Lasso, 0.0 = Ridge)
    alpha: f64,
    /// Number of coordinate descent iterations
    #[allow(dead_code)]
    iterations: usize,
    /// Whether algorithm converged
    #[allow(dead_code)]
    converged: bool,
}

impl Lm {
    /// Fit a linear model using ndarray views (recommended modern API)
    ///
    /// This implementation uses faer's column-pivoted QR decomposition to handle
    /// rank-deficient design matrices robustly, as is common in statistical modeling.
    ///
    /// # Arguments
    /// * `x` - Design matrix as ndarray view (n_observations × n_predictors)
    /// * `y` - Response vector as ndarray view (n_observations)
    ///
    /// # Example
    /// ```
    /// use ndarray::Array2;
    /// use stats_models::Lm;
    ///
    /// // Create design matrix with intercept
    /// let x = Array2::from_shape_vec((3, 2), vec![1.0, 1.0, 1.0, 2.0, 1.0, 3.0]).unwrap();
    /// let y = vec![3.0, 5.0, 7.0];
    ///
    /// let fit = Lm::fit_ndarray(x.view(), ndarray::Array1::from(y).view()).unwrap();
    /// ```
    pub fn fit_ndarray(x: ArrayView2<f64>, y: ArrayView1<f64>) -> Result<LmFit, ModelError> {
        let (n_rows, n_cols) = x.dim();

        if y.len() != n_rows {
            return Err(ModelError::InvalidModel(
                "Response vector length doesn't match number of observations".to_string(),
            ));
        }

        // Convert to faer matrices
        let x_mat = Mat::from_fn(n_rows, n_cols, |i, j| x[[i, j]]);
        let y_mat = Mat::from_fn(n_rows, 1, |i, _| y[i]);

        Self::fit_internal(x_mat, y_mat, n_rows, n_cols)
    }

    /// Fit a linear model using raw slices (legacy API for backward compatibility)
    ///
    /// This implementation uses faer's column-pivoted QR decomposition to handle
    /// rank-deficient design matrices robustly, as is common in statistical modeling.
    ///
    /// **Note**: Consider using `fit_ndarray` for better type safety and ergonomics.
    pub fn fit(
        x_data: &[f64],
        y_data: &[f64],
        n_rows: usize,
        n_cols: usize,
    ) -> Result<LmFit, ModelError> {
        if x_data.len() != n_rows * n_cols {
            return Err(ModelError::InvalidModel(
                "Design matrix dimensions don't match data".to_string(),
            ));
        }

        if y_data.len() != n_rows {
            return Err(ModelError::InvalidModel(
                "Response vector length doesn't match number of observations".to_string(),
            ));
        }

        // Create faer matrices from input data
        let x_mat = Mat::from_fn(n_rows, n_cols, |i, j| x_data[i * n_cols + j]);
        let y_mat = Mat::from_fn(n_rows, 1, |i, _| y_data[i]);

        Self::fit_internal(x_mat, y_mat, n_rows, n_cols)
    }

    /// Internal fitting logic shared by both APIs
    fn fit_internal(
        x_mat: Mat<f64>,
        y_mat: Mat<f64>,
        n_rows: usize,
        n_cols: usize,
    ) -> Result<LmFit, ModelError> {
        // Use column-pivoted QR for numerical stability with rank-deficient matrices
        let qr = x_mat.col_piv_qr();

        // Calculate rank from R matrix diagonal elements
        let r_matrix = qr.R();
        let tolerance = 1e-12;
        let mut rank = 0;
        for i in 0..r_matrix.nrows().min(r_matrix.ncols()) {
            if r_matrix[(i, i)].abs() > tolerance {
                rank += 1;
            }
        }

        // Handle rank-deficient matrices by checking for numerical instability
        let coefficients_mat = qr.solve_lstsq(&y_mat);

        // Check for numerical instability and apply correction if needed
        let has_instability =
            (0..coefficients_mat.nrows()).any(|i| coefficients_mat[(i, 0)].abs() > 1e10);

        let final_coefficients_mat = if has_instability {
            // For rank-deficient case, set coefficients for columns beyond rank to zero
            let mut corrected_coefs = Vec::new();
            for i in 0..coefficients_mat.nrows() {
                let coef = coefficients_mat[(i, 0)];
                if coef.abs() > 1e10 {
                    corrected_coefs.push(0.0);
                } else {
                    corrected_coefs.push(coef);
                }
            }
            Mat::from_fn(n_cols, 1, |i, _| corrected_coefs[i])
        } else {
            coefficients_mat
        };

        // Calculate fitted values: ŷ = X * β (using corrected coefficients)
        let fitted_mat = &x_mat * &final_coefficients_mat;

        // Calculate residuals: e = y - ŷ
        let residuals_mat = &y_mat - &fitted_mat;

        // Extract results to plain Vec<f64> for API
        let coefficients: Vec<f64> = (0..final_coefficients_mat.nrows())
            .map(|i| final_coefficients_mat[(i, 0)])
            .collect();

        let fitted_values: Vec<f64> = (0..fitted_mat.nrows())
            .map(|i| fitted_mat[(i, 0)])
            .collect();

        let residuals: Vec<f64> = (0..residuals_mat.nrows())
            .map(|i| residuals_mat[(i, 0)])
            .collect();

        // rank is already computed above using qr.rank()

        Ok(LmFit {
            coefficients,
            fitted_values,
            residuals,
            n_obs: n_rows,
            rank,
            x_matrix: x_mat,
        })
    }
}

impl LmFit {
    /// Get the number of observations used in the model
    pub fn n_obs(&self) -> usize {
        self.n_obs
    }

    /// Get the rank of the design matrix (number of linearly independent columns)
    pub fn rank(&self) -> usize {
        self.rank
    }

    /// Get degrees of freedom for error (n_obs - rank)
    pub fn df_resid(&self) -> usize {
        self.n_obs.saturating_sub(self.rank)
    }
}

impl Glm {
    /// Fit a generalized linear model using ndarray views
    ///
    /// This implementation uses the IRLS algorithm to fit GLMs with any
    /// exponential family distribution and link function.
    ///
    /// # Arguments
    /// * `x` - Design matrix as ndarray view (n_observations × n_predictors)
    /// * `y` - Response vector as ndarray view (n_observations)
    /// * `family` - Exponential family (Gaussian, Poisson, Binomial)
    /// * `start` - Optional starting values for coefficients
    /// * `config` - Optional IRLS configuration
    pub fn fit_ndarray<F>(
        x: ArrayView2<f64>,
        y: ArrayView1<f64>,
        family: F,
        start: Option<Array1<f64>>,
        config: Option<IrlsConfig>,
    ) -> Result<GlmFit, ModelError>
    where
        F: Family,
    {
        let (n_rows, n_cols) = x.dim();

        if y.len() != n_rows {
            return Err(ModelError::InvalidModel(
                "Response vector length doesn't match number of observations".to_string(),
            ));
        }

        let link = family.link();

        // Define closures for IRLS algorithm
        let link_fn = |mu: f64| link.link(mu);
        let inverse_link_fn = |eta: f64| link.inverse_link(eta);
        let mu_eta_fn = |eta: f64| link.mu_eta(eta);
        let variance_fn = |mu: f64| family.variance(mu);
        let dev_resid_fn = |y: f64, mu: f64| family.dev_resid(y, mu);

        let functions = optimcore::GlmFunctions {
            link_fn,
            inverse_link_fn,
            mu_eta_fn,
            variance_fn,
            dev_resid_fn,
        };

        // Run IRLS algorithm
        let irls_result = irls(x, y, functions, start, config)
            .map_err(|e| ModelError::LinearAlgebra(e.to_string()))?;

        // Calculate fitted values: μ = g⁻¹(X * β)
        let fitted_values: Vec<f64> = irls_result
            .linear_predictor
            .iter()
            .map(|&eta| inverse_link_fn(eta))
            .collect();

        // Calculate residuals: e = y - μ
        let residuals: Vec<f64> = y
            .iter()
            .zip(fitted_values.iter())
            .map(|(&y_val, &fitted)| y_val - fitted)
            .collect();

        // Convert ndarray to faer matrix for storage
        let x_matrix = Mat::from_fn(n_rows, n_cols, |i, j| x[[i, j]]);

        Ok(GlmFit {
            coefficients: irls_result.params.to_vec(),
            fitted_values,
            residuals,
            linear_predictor: irls_result.linear_predictor.to_vec(),
            n_obs: n_rows,
            x_matrix,
            deviance: irls_result.deviance,
            weights: irls_result.weights.to_vec(),
            iterations: irls_result.iterations,
            converged: irls_result.converged,
        })
    }
}

